+        int8_t *two_column_buf = src1;
+
+        for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
+        {
+            int8_t *two_col_ptr = two_column_buf;
+            int8_t *out = out_tensor;
+
+            for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
+            {
+                const long ker_y_start = cur_out_y * stride_y - pad_y;
+                const long ker_y_end = ker_y_start + ker_dim_y;
+                for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
+                {
+                    const long ker_x_start = cur_out_x * stride_x - pad_x;
+                    const long ker_x_end = ker_x_start + ker_dim_x;
+                    for (long cur_ker_y = ker_y_start; cur_ker_y < ker_y_end; cur_ker_y++)
+                    {
+                        for (long cur_ker_x = ker_x_start; cur_ker_x < ker_x_end; cur_ker_x++)
+                        {
+                            if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
+                            {
+                                nn_set_val_s8(two_col_ptr, -in_offset, in_tensor_ch);
+                            }
+                            else
+                            {
+                                nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, two_col_ptr, in_tensor_ch);
+                            }
+                            two_col_ptr += in_tensor_ch;
+                        }
+                    }
+
+                    /* Computation is filed for every 2 columns */
+                    if (two_col_ptr == two_column_buf + 2 * col)
