            vint8m1_t vptr_a1 = __riscv_vle8_v_i8m1(ptr_a1, vl);
            vint16m2_t vptr_b0_i16m2 = __riscv_vwsub_vx(vptr_b0, input_offset2, vl);
            vint16m2_t vptr_b1_i16m2 = __riscv_vwsub_vx(vptr_b1, input_offset2, vl);
            vl = __riscv_vsetvl_e16m2(col_count);
            vint16m2_t vptr_a0_i16m2 = __riscv_vsext_vf2(vptr_a0, vl);
            vint16m2_t vptr_a1_i16m2 = __riscv_vsext_vf2(vptr_a1, vl);
            vaccumulator_a = __riscv_vwmacc(vaccumulator_a, vptr_a0_i16m2, vptr_b0_i16m2, vl);    //ch_0_out_0 += a0 * b0;
            vaccumulator_b = __riscv_vwmacc(vaccumulator_b, vptr_a0_i16m2, vptr_b1_i16m2, vl);    //ch_0_out_1 += a0 * b1;
            vaccumulator_c = __riscv_vwmacc(vaccumulator_c, vptr_a1_i16m2, vptr_b0_i16m2, vl);    //ch_1_out_0 += a1 * b0;
            vaccumulator_d = __riscv_vwmacc(vaccumulator_d, vptr_a1_i16m2, vptr_b1_i16m2, vl);   //ch_1_out_1 += a1 * b1;
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;
        }

        vl = __riscv_vsetvl_e32m4(num_col_a);   //note the avl here
        vint32m1_t vch_0_out_0 = __riscv_vredsum(vaccumulator_a, vzero, vl);    //ch_0_out_0
        vint32m1_t vch_0_out_1 = __riscv_vredsum(vaccumulator_b, vzero, vl);    //ch_0_out_1
        vint32m1_t vch_1_out_0 = __riscv_vredsum(vaccumulator_c, vzero, vl);    //ch_1_out_0
        vint32m1_t vch_1_out_1 = __riscv_vredsum(vaccumulator_d, vzero, vl);    //ch_1_out_1

        vl = __riscv_vsetvl_e32m1(2);
        vch_0_out_0 = __riscv_vslideup(vch_0_out_0, vch_1_out_0, 1, vl);
        vch_0_out_1 = __riscv_vslideup(vch_0_out_1, vch_1_out_1, 1, vl);

        //add bias back
        if (bias)
        {
            vint32m1_t vbias = __riscv_vle32_v_i32m1(bias, vl);
            bias += vl;
            vch_0_out_0 = __riscv_vadd(vch_0_out_0, vbias, vl);
            vch_0_out_1 = __riscv_vadd(vch_0_out_1, vbias, vl);
        }

        //===== Quantize down =====
        vint32m1_t vout_shift = __riscv_vle32_v_i32m1(out_shift, vl);
        vint32m1_t vout_mult = __riscv_vle32_v_i32m1(out_mult, vl);
        vout_shift = __riscv_vrsub(vout_shift, 30, vl);

        vint64m2_t vout0_i64m2 = __riscv_vwmul(vch_0_out_0, vout_mult, vl);
        vint64m2_t vout1_i64m2 = __riscv_vwmul(vch_0_out_1, vout_mult, vl);
        vuint32m1_t vout_shift_unsigned = __riscv_vreinterpret_u32m1(vout_shift);
        vint32m1_t vout0 = __riscv_vnsra_wv_i32m1(vout0_i64m2, vout_shift_unsigned, vl);
        vint32m1_t vout1 = __riscv_vnsra_wv_i32m1(vout1_i64m2, vout_shift_unsigned, vl);
        vout0 = __riscv_vssra(vout0, 1, __RISCV_VXRM_RNU, vl);
        vout1 = __riscv_vssra(vout1, 1, __RISCV_VXRM_RNU, vl);

        // Add offset
        vout0 = __riscv_vadd(vout0, out_offset, vl);
        vout1 = __riscv_vadd(vout1, out_offset, vl);

        // Clamp the result
        vout0 = __riscv_vmax(vout0, activation_min, vl);
        vout0 = __riscv_vmin(vout0, activation_max, vl);
        vout1 = __riscv_vmax(vout1, activation_min, vl);
        vout1 = __riscv_vmin(vout1, activation_max, vl);

        //narrowing and store the results
        vl = __riscv_vsetvl_e16m1(2);
        vint32m2_t vout0_i32m2 =  __riscv_vlmul_ext_v_i32m1_i32m2(vout0);
        vint16m1_t vout0_i16m1 = __riscv_vnsra_wx_i16m1(vout0_i32m2, 0, vl);
        vint32m2_t vout1_i32m2 =  __riscv_vlmul_ext_v_i32m1_i32m2(vout1);
        vint16m1_t vout1_i16m1 = __riscv_vnsra_wx_i16m1(vout1_i32m2, 0, vl);
        vl = __riscv_vsetvl_e8m1(2);
        vint16m2_t vout0_i16m2 =  __riscv_vlmul_ext_v_i16m1_i16m2(vout0_i16m1);
        vint8m1_t vout0_i8m1 = __riscv_vnsra_wx_i8m1(vout0_i16m2, 0, vl);
        vint16m2_t vout1_i16m2 =  __riscv_vlmul_ext_v_i16m1_i16m2(vout1_i16m1);
        vint8m1_t vout1_i8m1 = __riscv_vnsra_wx_i8m1(vout1_i16m2, 0, vl);
        __riscv_vse8(out_0, vout0_i8m1, vl);
        __riscv_vse8(out_1, vout1_i8m1, vl);
        out_0 += vl;
        out_1 += vl;
        out_mult += vl;
        out_shift += vl;

        /* skip row */
        ptr_a0 += num_col_a;
        row_count--;
    }

    /* compute the last odd numbered row if any */
    vl = __riscv_vsetvl_e32m8(num_col_a);
    if (output_ch & 0x1)
    {
        /* setup pointers for B */
        const q7_t *ptr_b0 = input_b;
        const q7_t *ptr_b1 = ptr_b0 + num_col_a;
        long col_count = num_col_a;

        //clear v0~v15 (keep mac results)
        vint32m8_t vaccumulator_a = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
        vint32m8_t vaccumulator_b = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);

