            vint8m2_t vptr_a0 = __riscv_vle8_v_i8m2(ptr_a0, vl);
            vint8m2_t vptr_b0 = __riscv_vle8_v_i8m2(ptr_b0, vl);
            vint8m2_t vptr_b1 = __riscv_vle8_v_i8m2(ptr_b1, vl);
            vint16m4_t vtemp0 = __riscv_vwsub_vx(vptr_b0, input_offset2, vl);
            vint16m4_t vtemp1 = __riscv_vwsub_vx(vptr_b1, input_offset2, vl);
