        //===== Quantize down =====
        long out_mult_val = *out_mult,
             out_shift_val = 30 - *out_shift;

        vint64m2_t vsum0_i64m2 = __riscv_vwmul(vsum0, out_mult_val, vl);
        vsum0 = __riscv_vnsra_wx_i32m1(vsum0_i64m2, out_shift_val, vl);
        vsum0 = __riscv_vssra(vsum0, 1, __RISCV_VXRM_RNU, vl);

