        vl = __riscv_vsetvl_e16m1(2);
        vint32m2_t vsum0_i32m2 = __riscv_vlmul_ext_v_i32m1_i32m2(vsum0);
        vint16m1_t vresult_i16m1 = __riscv_vnsra_wx_i16m1(vsum0_i32m2, 0, vl);
        vl = __riscv_vsetvl_e8m1(2);
        vint16m2_t vresult_i16m2 = __riscv_vlmul_ext_v_i16m1_i16m2(vresult_i16m1);
        vint8m1_t vresult_i8m1 = __riscv_vnsra_wx_i8m1(vresult_i16m2, 0, vl);
        vl = __riscv_vsetvl_e8m1(1);
        __riscv_vse8(out_0, vresult_i8m1, vl);
        vl = __riscv_vsetvl_e16m1(2);
        vresult_i16m1 = __riscv_vreinterpret_v_i8m1_i16m1(vresult_i8m1);
        vresult_i16m1 = __riscv_vsra(vresult_i16m1, 8, vl);
        vl = __riscv_vsetvl_e8m1(1);
        vresult_i8m1 = __riscv_vreinterpret_v_i16m1_i8m1(vresult_i16m1);
        __riscv_vse8(out_1, vresult_i8m1, vl);
        out_0++;
        out_1++;
        out_mult++;
        out_shift++;
    }

    out_0 += output_ch;

    /* return the new output pointer with offset */
    return out_0;
#else
    //Note. vwmacc version v-ext algo is slightly better than vqmac version v-ext algo

