/**
 * @defgroup Support Support Functions
 * @brief Perform vector multiplication and data type conversion for Neural Network.
 *
 * @{
 */

/**
 * @brief           Duplicate the elements in a Q7 vector to a Q15 vector.
 *                  This is internally used function.
 * @param[in]       src         pointer of Q7 input vector
 * @param[out]      dst         pointer of Q15 output vector
 * @param[in]       size        element numbers in input/output vector
 * @return          None
 *
 * @b Example:
 * @code
 * #define SIZE 10
 * q7_t in_data[SIZE] = {...};
 * q15_t out_data[SIZE];
 *
 * nn_dup_s8_s16(in_data, out_data, SIZE);
 * @endcode
 */

void nn_dup_s8_s16(const q7_t * src, q15_t * dst, uint32_t size);

/**
 * @brief           Duplicate and reorder every two elements in a Q7 vector to
 *                  a Q15 vector. This is an internally used function.
 * @param[in]       src         pointer of Q7 input vector
 * @param[out]      dst         pointer of Q15 output vector
 * @param[in]       size        element numbers in input/output vector
 * @return          None
 *
 * @b Example:
 * @code
 * #define SIZE 10
 * q7_t in_data[SIZE] = {...};
 * q15_t out_data[SIZE];
 *
 * nn_dup_s8_s16_reordered(in_data, out_data, SIZE);
 * @endcode
 */

void nn_dup_s8_s16_reordered(const q7_t * src, q15_t * dst, uint32_t size);

void nn_dup_u8_u16_reordered(const u8_t * src, u16_t * dst, uint32_t size);

void nn_dup_s8_s16_offset(const q7_t *src,
                          q15_t *dst,
                          uint32_t block_size,
                          q15_t offset);

void static inline nn_dup_s16(const q15_t * src, q15_t * dst, uint32_t size)
{
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    long vl;
    long size2 = size;
    while(size2 > 0)
    {
        vl = __riscv_vsetvl_e16m8(size2);
        vint16m8_t vSrc = __riscv_vle16_v_i16m8(src, vl);
        __riscv_vse16(dst, vSrc, vl);
        src += vl;
        dst += vl;
        size2 -= vl;
    }
#elif defined(ENA_VEC_ISA)
    long vl;
    while(size > 0)
    {
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLH_V(NDS_VEC_V0, src);
        NDS_VEC_VSH_V(NDS_VEC_V0, dst);
        src += vl;
        dst += vl;
        size -= vl;
    }
#elif defined(NDS_TOOLCHAIN_RISCV)
    memcpy(dst, src, sizeof(*src) * size);
#endif
}

void static inline nn_dup_s8(const q7_t * src, q7_t * dst, uint32_t size)
{
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    long vl;
    long size2 = size;
    while(size2 > 0)
    {
        vl = __riscv_vsetvl_e8m8(size2);
        vint8m8_t vSrc = __riscv_vle8_v_i8m8(src, vl);
        __riscv_vse8(dst, vSrc, vl);
        src += vl;
        dst += vl;
        size2 -= vl;
    }
#elif defined(ENA_VEC_ISA)
    while(size > 0)
    {
        long vl;
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE8_V(NDS_VEC_V0, src);
        src += vl;
        size -= vl;
        NDS_VEC_VSE8_V(NDS_VEC_V0, dst);
        dst += vl;
    }
#else
    memcpy(dst, src, size);
#endif
}

//customized function for the VPU with the configuration of SIMD=VLEN/2
#if defined(ENA_VEC_ISA) || defined(ENA_VEC_INTRINSIC)
void static inline nn_dup_s8_v2(const q7_t * src, q7_t * dst, uint32_t size)
{
#ifdef ENA_VEC_INTRINSIC
    long vl;
    long size2 = size;
    while(size2 > 0)
    {
        vl = __riscv_vsetvl_e8m4(size2);
        vint8m4_t vSrc = __riscv_vle8_v_i8m4(src, vl);
        __riscv_vse8(dst, vSrc, vl);
        src += vl;
        dst += vl;
        size2 -= vl;
    }
#else
    //used vector registers: v0
    long vl;
    while(size > 0)
    {
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VLB_V(NDS_VEC_V0, src);
        NDS_VEC_VSB_V(NDS_VEC_V0, dst);
        src += vl;
        dst += vl;
        size -= vl;
    }
#endif
}
#endif

void static inline nn_dup_u8(const u8_t * src, u8_t * dst, uint32_t size)
{
#ifdef ENA_VEC_ISA
    //used vector registers: v0
    int32_t vl;
    while(size > 0)
    {
        NDS_VEC_VSETVLI_E8(vl, size);
        NDS_VEC_VLBU_V(NDS_VEC_V0, src);
        NDS_VEC_VSB_V(NDS_VEC_V0, dst);
        src += vl;
        dst += vl;
        size -= vl;
    }
#else
    memcpy(dst, src, size);
#endif
}

void static inline nn_set_zero_s64(q63_t *dst, uint32_t size)
{
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_ELEN64)
    long vl;
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E64, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);
    while(size > 0)
    {
        NDS_VEC_VSE64_V(NDS_VEC_V24, dst);
        dst += vl;
        size -= vl;
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E64, NDS_VEC_VTYPE_LMUL_M8);
    }
#else
    memset(dst, 0, sizeof(int64_t) * size);
#endif
}

void static inline nn_set_zero_s16(q15_t *dst, uint32_t size)
{
#ifdef ENA_VEC_ISA
    long vl;
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);
    while(size > 0)
    {
        NDS_VEC_VSH_V(NDS_VEC_V24, dst);
        dst += vl;
        size -= vl;
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
    }
#else
    // while(size-- > 0)
    // {
    //     *dst++ = 0;
    // }
    memset(dst, 0, sizeof(int16_t) * size);
#endif
}

void static inline nn_set_zero_s8(q7_t *dst, uint32_t size)
{
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    long vl;
    vl = __riscv_vsetvl_e8m8(size);
    vint8m8_t vZero = __riscv_vundefined_i8m8();
    vZero = __riscv_vand(vZero, 0, vl);
    while(size > 0)
    {
        __riscv_vse8(dst, vZero, vl);
        dst += vl;
        size -= vl;
        vl = __riscv_vsetvl_e8m8(size);
    }
#elif ENA_VEC_ISA
    long vl;
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);
    while(size > 0)
    {
        NDS_VEC_VSB_V(NDS_VEC_V24, dst);
        dst += vl;
        size -= vl;
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
    }
#else
    // while(size-- > 0)
    // {
    //     *dst++ = 0;
    // }
    memset(dst, 0, size);
#endif
}

void static inline nn_set_zero_u8(u8_t *dst, uint32_t size)
{
#ifdef ENA_VEC_ISA
    //Note. vector register v31 must be set to zero before calling this function
    int32_t vl;
    NDS_VEC_VSETVLI_E8(vl, size);
    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
    while(size > 0)
    {
        NDS_VEC_VSETVLI_E8(vl, size);
        NDS_VEC_VSB_V(NDS_VEC_V31, dst);
        dst += vl;
        size -= vl;
    }
#else
    memset(dst, 0, size);
#endif
}

void static inline nn_set_val_s8(q7_t *dst, q7_t val, uint32_t size)
{
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    long vl;
    vl = __riscv_vsetvl_e8m8(size);
    vint8m8_t vVal = __riscv_vmv_v_x_i8m8(val, vl);

    while (size > 0)
    {
        __riscv_vse8(dst, vVal, vl);
        dst += vl;
        size -= vl;
        vl = __riscv_vsetvl_e8m8(size);
    }
#elif ENA_VEC_ISA
    long vl;
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VMV_V_X(NDS_VEC_V0, val);

    while (size > 0)
    {
        NDS_VEC_VSE8_V(NDS_VEC_V0, dst);
        dst += vl;
        size -= vl;
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
    }
#else
    // while(size-- > 0)
    // {
    //     *dst++ = 0;
    // }
    memset(dst, val, size);
#endif
}

void static inline nn_set_val_s16(int16_t *dst, int16_t val, uint32_t size)
{
#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    long vl;
    vl = __riscv_vsetvl_e16m8(size);
    vint16m8_t vVal = __riscv_vmv_v_x_i16m8(val, vl);

    while (size > 0)
    {
        __riscv_vse16(dst, vVal, vl);
        dst += vl;
        size -= vl;
        vl = __riscv_vsetvl_e16m8(size);
    }
#elif ENA_VEC_ISA
    uint32_t vl;
    NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VMV_V_X(NDS_VEC_V0, val);

    while(size > 0)
    {
        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VSE16_V(NDS_VEC_V0, dst);
        dst += vl;
        size -= vl;
    }
#else
    while(size-- > 0)
    {
        *dst++ = val;
    }
#endif
}

// Following is a customized function for q7 fully-connected.
// This function will read every two inputs (in[n] and in[n+1]), duplicate them
// 4 times and store them to the destination with the reordered ordering of
// (in[n] in[n] in[n+1] in[n+1] in[n] in[n] in[n+1] in[n+1])
// (left hand side elements have lower index).
// The rest (size mod 3) elements are copied to the destination directly.
#ifdef ENA_VEC_ISA
void static inline nn_dup_s8_x4_reordered(const q7_t * src, q7_t * dst, uint32_t size)
{
#if 1   //version-1 (generate the load index at run time)
    int32_t vl, vl2;
    uint32_t sft_bit = 8;
    uint32_t size2 = (size >> 2) << 2;

#ifdef ENA_VEC_INTRINSIC
    //generate load index (swap the elements at index of 4n+1 and 4n+2)
    vl = __riscv_vsetvl_e8m1(size2);
    vuint8m1_t vIndex_u8 = __riscv_vid_v_u8m1(vl);
    vl = __riscv_vsetvl_e32m1(vl >> 2);
    vuint32m1_t vIndex_u32 = __riscv_vreinterpret_u32m1(vIndex_u8);
    //clear 4n+1 and 4n+2 index elements
    vuint32m1_t vtmp_a = __riscv_vand(vIndex_u32, 0xFF0000FF, vl);
    //select 4n+2 index elements
    vuint32m1_t vtmp_b = __riscv_vand(vIndex_u32, 0x00FF0000, vl);
    //shift 4n+2 index elements to 4n+1 position
    vtmp_b = __riscv_vsrl(vtmp_b, sft_bit, vl);
    vtmp_a = __riscv_vor(vtmp_a, vtmp_b, vl);
    //select 4n+1 index elements
    vtmp_b = __riscv_vand(vIndex_u32, 0x0000FF00, vl);
    //shift 4n+1 index elements to 4n+2 position
    vtmp_b = __riscv_vsll(vtmp_b, sft_bit, vl);
    //V0: load ordering index
    vtmp_a = __riscv_vor(vtmp_a, vtmp_b, vl);
    vuint8m1_t vbindex = __riscv_vreinterpret_u8m1(vtmp_a);

    q7_t *dst2 = dst+4;
    while(size2 > 0)
    {
        vl = __riscv_vsetvl_e8m1(size2);
        vint8m1_t vsrc_i8 = __riscv_vluxei8(src, vbindex, vl);
        vuint8m1_t vsrc_u8 = __riscv_vreinterpret_u8m1(vsrc_i8);
        vuint16m2_t vsum = __riscv_vwaddu_vx(vsrc_u8, 0, vl);
        vl2 = __riscv_vsetvl_e16m2(size2);
        vuint16m2_t vsum_sftl = __riscv_vsll(vsum, 8, vl2);
        vsum_sftl = __riscv_vor(vsum_sftl, vsum, vl2);

        //since the AndeSim now doesn't support SEW=64
        //thus, here we strided store the results to the destination twice
        vl2 = __riscv_vsetvl_e32m2(size2 >> 1);
        vuint32m2_t vresult = __riscv_vreinterpret_u32m2(vsum_sftl);
        __riscv_vsse32((u32_t *)dst, 8, vresult, vl2);
        __riscv_vsse32((u32_t *)dst2, 8, vresult, vl2);

        size2 -= vl;
        src += vl;
        dst += vl<<2;
        dst2 += vl<<2;
    }

    //rest
    size2 = size & 0x3u;
    while (size2 > 0u)
    {
        *dst++ = *src++;
        size2--;
    }
#else
    //generate load index (swap the elements at index of 4n+1 and 4n+2)
    NDS_VEC_VSETVLI_E8(vl, size2);
    NDS_VEC_VID_V(NDS_VEC_V1);      //temp index vector
    NDS_VEC_VSETVLI_E32(vl, vl>>2);
    //clear 4n+1 and 4n+2 index elements
    NDS_VEC_VAND_VX(NDS_VEC_V0, NDS_VEC_V1, 0xFF0000FF);
    //select 4n+2 index elements
    NDS_VEC_VAND_VX(NDS_VEC_V2, NDS_VEC_V1, 0x00FF0000);
    //shift 4n+2 index elements to 4n+1 position
    NDS_VEC_VSRL_VX(NDS_VEC_V2, NDS_VEC_V2, sft_bit);
    NDS_VEC_VOR_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V2);
