        size2 -= vl;
        src += vl;
        dst += vl<<2;
        dst2 += vl<<2;
    }

    //rest
    size2 = size & 0x3u;
    while (size2 > 0u)
    {
        *dst++ = *src++;
        size2--;
    }
#endif
