                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLE32_V(NDS_VEC_V1, pBias);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
                pBias += vl;
                NDS_VEC_VSE32_V(NDS_VEC_V0, pWt_contri);
                pWt_contri++;
                out_tensor_ch2--;
            }
        }
    }
    else
    {
        if (rhs_cols & 0x1)
        {
            long vl;
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

            for (long i = 0; (i + 2) <= out_tensor_ch; i += 2)
            {
                // unroll-1
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); // clean the accumulator for vd4dot
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);             // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
                NDS_VEC_VSE32_V(NDS_VEC_V0, pWt_contri);
                pWt_contri++;


                // unroll-2
                // we need to deal with the first nibble in the even index
                // out_tensor_ch specially
                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                // please note here we need to the data with vle8; otherwise, we
                // can't acces the high part of the specific byte
                NDS_VEC_VLE8_V(NDS_VEC_V29, pWt);
                NDS_VEC_VSRA_VI(NDS_VEC_V29, NDS_VEC_V29, 4);   //the first nibble of the even index out_tensor_ch
                pWt++;
                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VSEXT_VF4(NDS_VEC_V28, NDS_VEC_V29);

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); // clean the accumulator for vd4dot
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);             // const one for vd4dot

                // please note we only set the length to (rhs_cols-1) owing to the
                // first nibble has been dealed with the codes in above section
                rhs_cols2 = rhs_cols - 1;

                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
                NDS_VEC_VSE32_V(NDS_VEC_V0, pWt_contri);
                pWt_contri++;
            }

            if (out_tensor_ch & 0x1)
            {
                long vl;
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
                NDS_VEC_VSE32_V(NDS_VEC_V0, pWt_contri);
                pWt_contri++;
            }
        }
        else
        {
            long out_tensor_ch2 = out_tensor_ch;
            long vl;
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

            while (out_tensor_ch2 > 0)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
                NDS_VEC_VSE32_V(NDS_VEC_V0, pWt_contri);
                pWt_contri++;
                out_tensor_ch2--;
            }
        }
    }

    for (int32_t cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        int8_t *two_column_buf2 = two_column_buf;
        int8_t *out = out_tensor;

        for (int32_t cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
        {
            const int32_t base_idx_x = stride_x * cur_out_x - pad_x;
            for (int32_t cur_ker_x = 0; cur_ker_x < ker_dim_x; cur_ker_x++)
            {
                const int32_t k_x = base_idx_x + dilation_x * cur_ker_x;

                if (k_x < 0 || k_x >= in_tensor_dim_x)
                {
                    nn_set_val_s8(two_column_buf2, -in_offset, in_tensor_ch);
                }
                else
                {
                    nn_dup_s8(in_tensor + (k_x) * in_tensor_ch, two_column_buf2, in_tensor_ch);
                }
                two_column_buf2 += in_tensor_ch;
            }

            /* Computation is filed for every 2 columns */
            if (two_column_buf2 == two_column_buf + 2 * in_tensor_ch * ker_dim_x)
            {
                out = nn_mat_mult_kernel_s8_s8_s4_asym(ker_weight,
                                                       two_column_buf,
                                                       out_tensor_ch,
                                                       out_shift,
                                                       out_scale,
                                                       in_offset,
                                                       out_offset,
                                                       act_min,
                                                       act_max,
                                                       rhs_cols,
                                                       contri_buf,
                                                       out);

                /* counter reset */
                two_column_buf2 = two_column_buf;
            }
        }

        /* left-over because odd number of output pixels */
        if (two_column_buf2 != two_column_buf)
        {
            long vl;
            NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // cosnt zero for redsum

            // setup pointers for the kernel weight
            const int8_t *pWt_0 = ker_weight;
            // setup pointers for the quantization parameters
            const int32_t *out_shift2 = out_shift;
            const int32_t *out_scale2 = out_scale;

            long col_count = in_tensor_ch * ker_dim_x;
            if (col_count & 0x1)
            {
                for (long cur_out_ch = 0; (cur_out_ch + 2) <= out_tensor_ch; cur_out_ch += 2)
                {
                    // setup pointers for the input tensor
                    const int8_t *pIn = (int8_t *)two_column_buf;
                    // setup pointers for the kernel weight
                    const int8_t *pWt_1 = pWt_0 + (col_count >> 1);

                    long col_count2 = col_count;

                    // init the accumulator
                    NDS_VEC_VSETVLI(vl, col_count2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
                    NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0);

                    while(col_count2 >= maxvl_per_loop)
                    {
                        NDS_VEC_VSETVLI(vl, col_count2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
                        NDS_VEC_VLN8_V(NDS_VEC_V8, pWt_0);
                        NDS_VEC_VLE8_V(NDS_VEC_V16, pIn);

                        // special process for the non-byte alignement access
                        NDS_VEC_VLN8_V(NDS_VEC_V12, pWt_1);
                        pWt_1 += vl >> 1;
                        long tmp_4b_low = (int8_t)(*pWt_1 << 4) >> 4;
                        NDS_VEC_VSLIDE1DOWN_VX(NDS_VEC_V12, NDS_VEC_V12, tmp_4b_low);

                        pWt_0 += vl >> 1;
                        pIn += vl;
                        col_count2 -= vl;

                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
                        NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                        NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V12);
                    }

                    //extra process for the case of elements to be dot producted is not a mutiple of 4
                    if(col_count2 > 0)
                    {
                        //clean one of the dot product source
                        long tmp_avl;
                        tmp_avl = col_count2 + 3;
                        NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
                        NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);

                        // special process for the non-byte alignement access
                        NDS_VEC_VSETVLI(vl, col_count2 + 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
                        NDS_VEC_VLN8_V(NDS_VEC_V12, pWt_1);
                        NDS_VEC_VSLIDE1DOWN_VX(NDS_VEC_V12, NDS_VEC_V12, 0);

                        NDS_VEC_VSETVLI(vl, col_count2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
                        NDS_VEC_VLN8_V(NDS_VEC_V8, pWt_0);
                        NDS_VEC_VLE8_V(NDS_VEC_V16, pIn);
                        pWt_0 += vl >> 1;
                        pWt_1 += vl >> 1;
                        pIn += vl;
                        col_count2 -= vl;

                        vl = (vl + 3) >> 2;
                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
                        NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                        NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V12);
                    }

