/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// Convolution Functions

int32_t riscv_nn_conv_HWC_s8_s8_s4_asym_bias_any(const int8_t * in_tensor,
                                                 const int32_t in_tensor_dim_x,
                                                 const int32_t in_tensor_dim_y,
                                                 const int32_t in_tensor_ch,
                                                 const int32_t in_tensor_batch,
                                                 const int8_t * ker_weight,
                                                 const int32_t out_tensor_ch,
                                                 const int32_t ker_dim_x,
                                                 const int32_t ker_dim_y,
                                                 const int32_t pad_x,
                                                 const int32_t pad_y,
                                                 const int32_t stride_x,
                                                 const int32_t stride_y,
                                                 const int32_t * bias,
                                                 int8_t * out_tensor,
                                                 const int32_t * out_shift,
                                                 const int32_t * out_scale,
                                                 const int32_t out_offset,    //value is in the range of [-128, 127]
                                                 const int32_t in_offset,     //value is in the range of [-127, 128]
                                                 const int32_t act_min,
                                                 const int32_t act_max,
                                                 const int32_t out_tensor_dim_x,
                                                 const int32_t out_tensor_dim_y,
                                                 const int32_t dilation_x,
                                                 const int32_t dilation_y,
                                                 int8_t * in_tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_UNPACK_S4_TO_TMP_BUF) && defined(ENA_VEC_ELEN64) // version-1 algo: unpack the 4-bit weight into a temporary buffer
    const int32_t rhs_cols = ker_dim_y * ker_dim_x * in_tensor_ch;
    long maxvl_per_loop;
    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);

    //--- calculate the buffer address ---
    const long align_byte = sizeof(long);
    // buffer-1
    int8_t *two_column_buf = in_tmp_buf;
    two_column_buf = (int8_t*)nn_align((unsigned long)two_column_buf, align_byte);      // align the starting addresss
    int8_t *unpacked_ker_wt = two_column_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(*in_tensor);
    // buffer-2
    unpacked_ker_wt = (int8_t*)nn_align((unsigned long)unpacked_ker_wt, align_byte);    // align the starting addresss
    // buffer-3
    int32_t *contri_buf = (int32_t*)(unpacked_ker_wt + out_tensor_ch * in_tensor_ch * ker_dim_y * ker_dim_x);
    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);             // align the starting addresss

    // calculate the weight contribution and unpack the ker_weight
    const int8_t *pWt = ker_weight;
    int8_t *pUnpacked_wt = unpacked_ker_wt;
    int32_t *pContri_buf = contri_buf;
    const int32_t *pBias = bias;

    if (pBias != NULL)
    {
        if (rhs_cols & 0x1)
        {
            long vl;
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

            for (long i = 0; (i + 2) <= out_tensor_ch; i += 2)
            {
                // unroll-1
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); // clean the accumulator for vd4dot
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);             // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLE32_V(NDS_VEC_V1, pBias);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
                pBias += vl;
                NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
                pContri_buf++;


                // unroll-2
                // we need to deal with the first nibble in the even index
                // out_tensor_ch specially
                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                // please note here we need to the data with vle8; otherwise, we
                // can't acces the high part of the specific byte
                NDS_VEC_VLE8_V(NDS_VEC_V29, pWt);
                NDS_VEC_VSRA_VI(NDS_VEC_V29, NDS_VEC_V29, 4);   //the first nibble of the even index out_tensor_ch
                NDS_VEC_VSE8_V(NDS_VEC_V29, pUnpacked_wt);
                pWt++;
                pUnpacked_wt += vl;
                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VSEXT_VF4(NDS_VEC_V28, NDS_VEC_V29);

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); // clean the accumulator for vd4dot
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);             // const one for vd4dot

                // please note we only set the length to (rhs_cols-1) owing to the
                // first nibble has been dealed with the codes in above section
                rhs_cols2 = rhs_cols - 1;

                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLE32_V(NDS_VEC_V1, pBias);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
                pBias += vl;
                NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
                pContri_buf++;
            }

            if (out_tensor_ch & 0x1)
            {
                long vl;
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLE32_V(NDS_VEC_V1, pBias);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
                pBias += vl;
                NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
                pContri_buf++;
            }
        }
        else
        {
            long out_tensor_ch2 = out_tensor_ch;
            long vl;
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

            while (out_tensor_ch2 > 0)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLE32_V(NDS_VEC_V1, pBias);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
                pBias += vl;
                NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
                pContri_buf++;
                out_tensor_ch2--;
            }
        }
    }
    else
    {
        if (rhs_cols & 0x1)
        {
            long vl;
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

            for (long i = 0; (i + 2) <= out_tensor_ch; i += 2)
            {
                // unroll-1
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); // clean the accumulator for vd4dot
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);             // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
                NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
                pContri_buf++;


                // unroll-2
                // we need to deal with the first nibble in the even index
                // out_tensor_ch specially
                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                // please note here we need to the data with vle8; otherwise, we
                // can't acces the high part of the specific byte
                NDS_VEC_VLE8_V(NDS_VEC_V29, pWt);
                NDS_VEC_VSRA_VI(NDS_VEC_V29, NDS_VEC_V29, 4);   //the first nibble of the even index out_tensor_ch
                NDS_VEC_VSE8_V(NDS_VEC_V29, pUnpacked_wt);
                pWt++;
                pUnpacked_wt += vl;
                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VSEXT_VF4(NDS_VEC_V28, NDS_VEC_V29);

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); // clean the accumulator for vd4dot
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);             // const one for vd4dot

                // please note we only set the length to (rhs_cols-1) owing to the
                // first nibble has been dealed with the codes in above section
                rhs_cols2 = rhs_cols - 1;

                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
                NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
                pContri_buf++;
            }

            if (out_tensor_ch & 0x1)
            {
                long vl;
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
                NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
                pContri_buf++;
            }
        }
        else
        {
            long out_tensor_ch2 = out_tensor_ch;
            long vl;
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

            while (out_tensor_ch2 > 0)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
                NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot

                while(rhs_cols2 > 0)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    NDS_VEC_VSE8_V(NDS_VEC_V16, pUnpacked_wt);
                    pWt += vl >> 1;
                    pUnpacked_wt += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
                NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
                pContri_buf++;
                out_tensor_ch2--;
            }
        }
    }

    for (int32_t cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        int8_t *two_column_buf2 = two_column_buf;
        int8_t *out = out_tensor;
        int32_t lhs_rows = 0;

        for (int32_t cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
        {
            for (int32_t cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
            {
                const int32_t base_idx_x = stride_x * cur_out_x - pad_x;
                const int32_t base_idx_y = stride_y * cur_out_y - pad_y;

                for (int32_t cur_ker_y = 0; cur_ker_y < ker_dim_y; cur_ker_y++)
                {
                    for (int32_t cur_ker_x = 0; cur_ker_x < ker_dim_x; cur_ker_x++)
                    {
                        const int32_t k_y = base_idx_y + dilation_y * cur_ker_y;
                        const int32_t k_x = base_idx_x + dilation_x * cur_ker_x;

                        if (k_y < 0 || k_y >= in_tensor_dim_y || k_x < 0 || k_x >= in_tensor_dim_x)
                        {
                            nn_set_val_s8(two_column_buf2, -in_offset, in_tensor_ch);
                        }
                        else
                        {
                            nn_dup_s8(in_tensor + (k_y * in_tensor_dim_x + k_x) * in_tensor_ch, two_column_buf2, in_tensor_ch);
                        }
                        two_column_buf2 += in_tensor_ch;
                    }
                }

                lhs_rows++;
                /* Computation is filed for every 2 columns */
                if (lhs_rows == 2)
                {
                    out = nn_mat_mult_kernel_s8_offset_v2(unpacked_ker_wt,
                                                          two_column_buf,
                                                          out_tensor_ch,
                                                          out_shift,
                                                          out_scale,
                                                          in_offset,
                                                          out_offset,
                                                          act_min,
                                                          act_max,
                                                          rhs_cols,
                                                          contri_buf,
                                                          out);

                    /* counter reset */
                    two_column_buf2 = two_column_buf;
                    lhs_rows = 0;
                }
            }
        }

        /* Handle left over columns */
        if (lhs_rows != 0)
        {
            long vl;
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // cosnt zero for redsum

            // setup pointers for the kernel weight
            const int8_t *pWt_0 = unpacked_ker_wt;
            // setup pointers for the quantization parameters
            const int32_t *out_shift2 = out_shift;
            const int32_t *out_scale2 = out_scale;

            long col_count = in_tensor_ch * ker_dim_y * ker_dim_x;
            for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
            {
                // setup pointers for the input tensor
                const int8_t *pIn = (int8_t *)two_column_buf;

                // init the accumulator
                long col_count2 = col_count;
                NDS_VEC_VSETVLI(vl, col_count2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);

                while(col_count2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, col_count2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, pWt_0);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, pIn);
                    pWt_0 +=vl;
                    pIn += vl;
                    col_count2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //extra process for the case of elements to be dot producted is not a mutiple of 4
                if(col_count2 > 0)
                {
                    //clean one of the dot product source
                    long tmp_avl;
                    tmp_avl = col_count2 + 3;
                    NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);

                    NDS_VEC_VSETVLI(vl, col_count2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, pWt_0);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, pIn);
                    pWt_0 += vl;
                    pIn += vl;
                    col_count2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);

                //add input_offset back
                int32_t *pContri_buf = &contri_buf[cur_out_ch];
                NDS_VEC_VLE32_V(NDS_VEC_V4, pContri_buf);
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);

                //===== Quantize down =====
                NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift2);
                NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale2);
                NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);

                NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
                NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
                NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);

                // Add offset
                NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);

                // Clamp the result
                NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
                NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);

                //narrowing and store the results
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
                NDS_VEC_VSE8_V(NDS_VEC_V4, out);
                out += vl;
                out_scale2 += vl;
                out_shift2 += vl;
            }
        }

        /* Advance to the next batch */
        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        out_tensor += (out_tensor_dim_y * out_tensor_dim_x * out_tensor_ch);
    }
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64) // version-2 algo: unpack the 4-bit weight on the fly whithin instructions
    const long rhs_cols = ker_dim_y * ker_dim_x * in_tensor_ch;
    long maxvl_per_loop;

    //--- calculate the buffer address ---
    const long align_byte = sizeof(long);
    // buffer-1
    int8_t *two_column_buf = in_tmp_buf;
    two_column_buf = (int8_t*)nn_align((unsigned long)two_column_buf, align_byte);  // align the starting addresss
    // buffer-2
    int32_t *contri_buf = (int32_t*)(two_column_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(*in_tensor));
    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);         // align the starting addresss

    // calculate the weight contribution
    const int8_t *pWt = ker_weight;
    int32_t *pContri_buf = contri_buf;
    const int32_t *pBias = bias;
    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);

    if (pBias != NULL)
    {
        if (rhs_cols & 0x1)
        {
            long vl;
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

            for (long i = 0; (i + 2) <= out_tensor_ch; i += 2)
            {
                // unroll-1
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); // clean the accumulator for vd4dot
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);             // const one for vd4dot

                long rhs_cols2 = rhs_cols;
                while(rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLN8_V(NDS_VEC_V16, pWt);
                    pWt += vl >> 1;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
                }

                //clean one of the dot product source
                long tmp_avl;
                tmp_avl = rhs_cols2 + 3;
