                    pWt++;
                    int8_t wt_val_low  = (int8_t)(packed_wt_val << 4) >> 4;
                    int8_t wt_val_high = packed_wt_val >> 4;
                    contribution_0 += wt_val_low + wt_val_high;
                    *pUnpacked_wt++ = wt_val_low;
                    *pUnpacked_wt++ = wt_val_high;
                }

                // the last nibble of even index out_tensor_ch and the first nibble
                // of odd index out_tensor_ch
                int8_t packed_wt_val = *pWt;
                pWt++;
                int8_t wt_val_low  = (int8_t)(packed_wt_val << 4) >> 4;
                int8_t wt_val_high = packed_wt_val >> 4;
                contribution_0 += wt_val_low;
                contribution_1 += wt_val_high;
                *pUnpacked_wt++ = wt_val_low;
                *pUnpacked_wt++ = wt_val_high;

                for (long j = 0; (j + 2) <= rhs_cols; j += 2)
                {
                    int8_t packed_wt_val = *pWt;
                    pWt++;
                    int8_t wt_val_low  = (int8_t)(packed_wt_val << 4) >> 4;
                    int8_t wt_val_high = packed_wt_val >> 4;
                    contribution_1 += wt_val_low + wt_val_high;
                    *pUnpacked_wt++ = wt_val_low;
                    *pUnpacked_wt++ = wt_val_high;
                }

                // add input_offset contribution back
                contribution_0 *= in_offset;
                contribution_1 *= in_offset;

                contri_buf[i]     = contribution_0;
                contri_buf[i + 1] = contribution_1;
            }

            if (out_tensor_ch & 0x1)
            {
                long contribution_0 = 0;
                for (long j = 0; (j + 2) <= rhs_cols; j += 2)
                {
                    int8_t packed_wt_val = *pWt;
                    pWt++;
                    int8_t wt_val_low  = (int8_t)(packed_wt_val << 4) >> 4;
                    int8_t wt_val_high = packed_wt_val >> 4;
                    contribution_0 += wt_val_low + wt_val_high;
                    *pUnpacked_wt++ = wt_val_low;
                    *pUnpacked_wt++ = wt_val_high;
                }

                // the remain nibble
                int8_t packed_wt_val = *pWt;
                int8_t wt_val_low  = (int8_t)(packed_wt_val << 4) >> 4;
                contribution_0 += wt_val_low;
                *pUnpacked_wt++ = wt_val_low;

                // add input_offset contribution back
                contribution_0 *= in_offset;

                contri_buf[out_tensor_ch - 1] = contribution_0;
            }
        }
        else
        {
            for (long i = 0; i < out_tensor_ch; i++)
            {
                long contribution = 0;
                for (long j = 0; (j + 2) <= rhs_cols; j += 2)
                {
                    int8_t packed_wt_val = *pWt;
                    pWt++;
                    int8_t wt_val_low  = (int8_t)(packed_wt_val << 4) >> 4;
                    int8_t wt_val_high = packed_wt_val >> 4;
                    contribution += wt_val_low + wt_val_high;
                    *pUnpacked_wt++ = wt_val_low;
                    *pUnpacked_wt++ = wt_val_high;
                }

                // add input_offset contribution back
                contribution *= in_offset;

                contri_buf[i] = contribution;
            }
        }
    }


    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        int8_t *two_column_buf2 = two_column_buf;
        int8_t *out = out_tensor;
        long lhs_rows = 0;

        for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
        {
            for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
            {
                const long base_idx_x = stride_x * cur_out_x - pad_x;
                const long base_idx_y = stride_y * cur_out_y - pad_y;

                for (long cur_ker_y = 0; cur_ker_y < ker_dim_y; cur_ker_y++)
                {
                    for (long cur_ker_x = 0; cur_ker_x < ker_dim_x; cur_ker_x++)
                    {
                        const long k_y = base_idx_y + dilation_y * cur_ker_y;
                        const long k_x = base_idx_x + dilation_x * cur_ker_x;

                        if (k_y < 0 || k_y >= in_tensor_dim_y || k_x < 0 || k_x >= in_tensor_dim_x)
                        {
                            nn_set_val_s8(two_column_buf2, -in_offset, in_tensor_ch);
                        }
                        else
                        {
                            nn_dup_s8(in_tensor + (k_y * in_tensor_dim_x + k_x) * in_tensor_ch, two_column_buf2, in_tensor_ch);
                        }
                        two_column_buf2 += in_tensor_ch;
                    }
                }

                lhs_rows++;
                /* Computation is filed for every 2 columns */
                if (lhs_rows == 2)
                {
                    out = nn_mat_mult_kernel_s8_offset_v2(unpacked_ker_wt,
                                                          two_column_buf,
                                                          out_tensor_ch,
                                                          out_shift,
                                                          out_scale,
                                                          in_offset,
                                                          out_offset,
                                                          act_min,
                                                          act_max,
                                                          rhs_cols,
                                                          contri_buf,
                                                          out);

                    /* counter reset */
                    two_column_buf2 = two_column_buf;
                    lhs_rows = 0;
                }
            }
        }

        /* Handle left over columns */
        if (lhs_rows != 0)
        {
            const int8_t *pUnpacked_wt = unpacked_ker_wt;
            for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
            {
                long sum = 0;

                /* Point to the beginning of the im2col buffer where the input is available as a rearranged column */
                const int8_t *pIn = (int8_t *)two_column_buf;

                long col_count = rhs_cols;
                while (col_count >= SIMD_NUM_Q7)
                {
                    suni_t wt_s8 = simd_load_8((s8_t*)pUnpacked_wt, 0);
                    suni_t in_s8 = simd_load_8((s8_t*)pIn, 0);
                    sum = NDS_DSP_SMAQA(sum, wt_s8.l0, in_s8.l0);
                    col_count -= SIMD_NUM_Q7;
                    pUnpacked_wt += SIMD_NUM_Q7;
                    pIn += SIMD_NUM_Q7;
                }
                while (col_count > 0)
                {
                    int8_t wt_val = *pUnpacked_wt++;
                    int8_t in_val = *pIn++;
                    sum += wt_val * in_val;
                    col_count--;
                }

                //add extra contribution back
                sum += contri_buf[cur_out_ch];

                sum = nn_requantize(sum, out_scale[cur_out_ch], out_shift[cur_out_ch]);
                sum += out_offset;
                sum = MAX(sum, act_min);
                sum = MIN(sum, act_max);
                *out++ = sum;
            }
        }

        /* Advance to the next batch */
        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        out_tensor += (out_tensor_dim_y * out_tensor_dim_x * out_tensor_ch);
    }
#else
    (void)in_tmp_buf;
    int32_t i_out_ch, i_out_y, i_out_x, i_input_ch, i_ker_y, i_ker_x;
    int32_t conv_out;

    int32_t i_batch;
    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
    {
        for (i_out_ch = 0; i_out_ch < out_tensor_ch; i_out_ch++)
        {
            for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
            {
                for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
                {
                    conv_out = 0;
                    if (bias)
                    {
                        conv_out = bias[i_out_ch];
                    }

                    const int32_t base_idx_y = stride_y * i_out_y - pad_y;
                    const int32_t base_idx_x = stride_x * i_out_x - pad_x;
                    const int32_t start_y_max = (-base_idx_y + dilation_y - 1) / dilation_y;
                    const int32_t start_x_max = (-base_idx_x + dilation_x - 1) / dilation_x;
                    const int32_t ker_y_start = MAX(0, start_y_max);
                    const int32_t ker_x_start = MAX(0, start_x_max);
                    const int32_t end_min_y = (in_tensor_dim_y - base_idx_y + dilation_y - 1) / dilation_y;
                    const int32_t end_min_x = (in_tensor_dim_x - base_idx_x + dilation_x - 1) / dilation_x;
                    const int32_t ker_y_end = MIN(ker_dim_y, end_min_y);
                    const int32_t ker_x_end = MIN(ker_dim_x, end_min_x);

                    for (i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
                    {
                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
                        {
                            const int32_t in_row = base_idx_y + dilation_y * i_ker_y;
                            const int32_t in_col = base_idx_x + dilation_x * i_ker_x;
                            int8_t *pIn = (int8_t*)&in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch];
                            long wt_idx_4b = i_out_ch * in_tensor_ch * ker_dim_y * ker_dim_x + (i_ker_y * ker_dim_x + i_ker_x) * in_tensor_ch;
                            long wt_idx_8b = wt_idx_4b >> 1;
                            int8_t *pWt = (int8_t*)&ker_weight[wt_idx_8b];

                            if (wt_idx_4b & 0x1)   // odd index
                            {
                                {
                                    int8_t in_val = *pIn;
                                    int8_t packed_wt_val = *pWt;
                                    int8_t wt_val = (int8_t)(packed_wt_val >> 4);
                                    pIn++;
                                    pWt++;

                                    conv_out += ((int32_t)in_val + in_offset) * wt_val;
                                }
                                for (i_input_ch = 1; (i_input_ch+2) <= in_tensor_ch; i_input_ch += 2)
                                {
                                    int8_t in_val_0 = *pIn;
                                    int8_t in_val_1 = *(pIn+1);
                                    int8_t packed_wt_val = *pWt;
                                    int8_t wt_val_0 = (int8_t)(packed_wt_val << 4) >> 4;
                                    int8_t wt_val_1 = (int8_t)(packed_wt_val >> 4);
                                    pIn += 2;
                                    pWt++;

                                    conv_out += ((int32_t)in_val_0 + in_offset) * wt_val_0;
                                    conv_out += ((int32_t)in_val_1 + in_offset) * wt_val_1;
                                }
                            }
                            else
                            {
                                for (i_input_ch = 0; (i_input_ch+2) <= in_tensor_ch; i_input_ch += 2)
                                {
                                    int8_t in_val_0 = *pIn;
                                    int8_t in_val_1 = *(pIn+1);
                                    int8_t packed_wt_val = *pWt;
                                    int8_t wt_val_0 = (int8_t)(packed_wt_val << 4) >> 4;
                                    int8_t wt_val_1 = (int8_t)(packed_wt_val >> 4);
                                    pIn += 2;
                                    pWt++;

                                    conv_out += ((int32_t)in_val_0 + in_offset) * wt_val_0;
                                    conv_out += ((int32_t)in_val_1 + in_offset) * wt_val_1;
                                }
                                if (in_tensor_ch & 0x1)
                                {
                                    int8_t in_val = *pIn;
                                    int8_t packed_wt_val = *pWt;
                                    int8_t wt_val = (int8_t)(packed_wt_val << 4) >> 4;

                                    conv_out += ((int32_t)in_val + in_offset) * wt_val;
                                }
                            }
                        }
                    }
                    conv_out = nn_requantize(conv_out, out_scale[i_out_ch], out_shift[i_out_ch]);
                    conv_out += out_offset;
                    conv_out = MAX(conv_out, act_min);
                    conv_out = MIN(conv_out, act_max);
                    out_tensor[i_out_ch + (i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch] = (int8_t)conv_out;
                }
            }
        }

        /* Advance to the next batch */
        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
    }
#endif  //ENA_EMPTY_FUN

    /* Return to application */
    return 0;
}

int32_t riscv_nn_conv_HWC_s8_s8_s4_asym_bias_any_get_buffer_size(const int32_t in_tensor_ch,
                                                                 const int32_t ker_dim_x,
                                                                 const int32_t ker_dim_y,
                                                                 const int32_t out_tensor_ch)
{
    // return the required buffer size in byte
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_UNPACK_S4_TO_TMP_BUF)  // version-1 algo: unpack the 4-bit weight into a temporary buffer
    const long align_byte = sizeof(long);

    // two col buffer
    int32_t buf_size = 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t);
    buf_size += align_byte - 1;     //extra size for aligning

    // buffer for the unpacked weight
    buf_size += out_tensor_ch * in_tensor_ch * ker_dim_y * ker_dim_x;
    buf_size += align_byte - 1;     //extra size for aligning

    // buffer for extra contribution
    buf_size += out_tensor_ch * sizeof(int32_t);
    buf_size += align_byte - 1;     //extra size for aligning

    return buf_size;
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)      // version-2 algo: unpack the 4-bit weight on the fly whithin instructions
    const long align_byte = sizeof(long);

    // two col buffer
    int32_t buf_size = 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t);
    buf_size += align_byte - 1;     //extra size for aligning

    // buffer for extra contribution
    buf_size += out_tensor_ch * sizeof(int32_t);
    buf_size += align_byte - 1;     //extra size for aligning

    return buf_size;
#elif defined(ENA_DSP_ISA)
    const long align_byte = sizeof(long);

    // two col buffer
    int32_t buf_size = 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t);
    buf_size += align_byte - 1;     //extra size for aligning

    // buffer for the unpacked weight
    buf_size += out_tensor_ch * in_tensor_ch * ker_dim_y * ker_dim_x;
    buf_size += align_byte - 1;     //extra size for aligning

    // buffer for weight contribution
    buf_size += out_tensor_ch * sizeof(int32_t);
    buf_size += align_byte - 1;     //extra size for aligning

    return buf_size;
#else
    (void)in_tensor_ch;
    (void)ker_dim_x;
    (void)ker_dim_y;
    return 0;
#endif
}

