//// Convolution Functions

q7_t *nn_mat_mult_kernel_s8_offset(const q7_t *input_a,
                                   const q7_t *input_b,
                                   const uint16_t output_ch,
                                   const int32_t *out_shift,
                                   const int32_t *out_mult,
                                   const int32_t input_offset,     //value is in the range of [-127, 128]
                                   const int32_t out_offset,       //value is in the range of [-128, 127]
                                   const int16_t activation_min,
                                   const int16_t activation_max,
                                   const uint16_t num_col_a,
                                   const int32_t *const output_bias,
                                   q7_t *out_0)
{
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
    /* set up the second output pointers */
    q7_t *out_1 = out_0 + output_ch;
    const int32_t *bias = output_bias;

    long row_count = output_ch >> 1;
    const q7_t *ptr_a0 = input_a;

    long vl;
    long vlenb = NDS_VEC_CSR_GET_VLENB();

    vint32m1_t vZero_e0 = __riscv_vand(__riscv_vundefined_i32m1(), 0, 1);    //const zero for redsum

    /* this loop over rows in A */
    while (row_count)
    {
        vl = __riscv_vsetvl_e8m2(num_col_a);
        vint8m2_t vOne_i8m2 = __riscv_vmv_v_x_i8m2(1, vl);                   //const one

        /* setup pointers for B */
        const q7_t *ptr_b0 = input_b;
        const q7_t *ptr_b1 = ptr_b0 + num_col_a;

        /* align the second pointer for A */
        const q7_t *ptr_a1 = ptr_a0 + num_col_a;

        long col_count = num_col_a;

        // init the accumulator
        vl = __riscv_vsetvl_e32m2(num_col_a);
        vint32m2_t vAcc0 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc1 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc2 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc3 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc_wt_0 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);
        vint32m2_t vAcc_wt_1 = __riscv_vand(__riscv_vundefined_i32m2(), 0, vl);

        while(col_count >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M2))
        {
            vl = __riscv_vsetvl_e8m2(col_count);
            vint8m2_t vA0_i8m2 = __riscv_vle8_v_i8m2(ptr_a0, vl);
            vint8m2_t vA1_i8m2 = __riscv_vle8_v_i8m2(ptr_a1, vl);
            vint8m2_t vB0_i8m2 = __riscv_vle8_v_i8m2(ptr_b0, vl);
            vint8m2_t vB1_i8m2 = __riscv_vle8_v_i8m2(ptr_b1, vl);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            vl = __riscv_vsetvl_e32m2(vl);
            vAcc0 = __riscv_vd4dots_vv_i32m2_tu(vAcc0, vA0_i8m2, vB0_i8m2, vl);     //ch_0_out_0 += a0 * b0;
            vAcc1 = __riscv_vd4dots_vv_i32m2_tu(vAcc1, vA0_i8m2, vB1_i8m2, vl);     //ch_0_out_1 += a0 * b1;
            vAcc2 = __riscv_vd4dots_vv_i32m2_tu(vAcc2, vA1_i8m2, vB0_i8m2, vl);     //ch_1_out_0 += a1 * b0;
            vAcc3 = __riscv_vd4dots_vv_i32m2_tu(vAcc3, vA1_i8m2, vB1_i8m2, vl);     //ch_1_out_1 += a1 * b1;
            vAcc_wt_0 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_0, vA0_i8m2, vOne_i8m2, vl);    //sum_input_a0 += a0;
            vAcc_wt_1 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_1, vA1_i8m2, vOne_i8m2, vl);    //sum_input_a1 += a1;
        }

        //extra process for the case of elements to be dot producted is not a mutiple of 4
        if(col_count > 0)
        {
            //clean one of the dot product source
            vl = __riscv_vsetvl_e8m2(col_count+3);
            vint8m2_t vA0_i8m2 = __riscv_vand(__riscv_vundefined_i8m2(), 0, vl);
            vint8m2_t vA1_i8m2 = __riscv_vand(__riscv_vundefined_i8m2(), 0, vl);
            vint8m2_t vB0_i8m2, vB1_i8m2;

            vl = __riscv_vsetvl_e8m2(col_count);
            vA0_i8m2 = __riscv_vle8_v_i8m2_tu(vA0_i8m2, ptr_a0, vl);
            vA1_i8m2 = __riscv_vle8_v_i8m2_tu(vA1_i8m2, ptr_a1, vl);
            vB0_i8m2 = __riscv_vle8_v_i8m2(ptr_b0, vl);
            vB1_i8m2 = __riscv_vle8_v_i8m2(ptr_b1, vl);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            vl = (vl + 3) >> 2;
            vl = __riscv_vsetvl_e32m2(vl);
            vAcc0 = __riscv_vd4dots_vv_i32m2_tu(vAcc0, vA0_i8m2, vB0_i8m2, vl);     //ch_0_out_0 += a0 * b0;
            vAcc1 = __riscv_vd4dots_vv_i32m2_tu(vAcc1, vA0_i8m2, vB1_i8m2, vl);     //ch_0_out_1 += a0 * b1;
            vAcc2 = __riscv_vd4dots_vv_i32m2_tu(vAcc2, vA1_i8m2, vB0_i8m2, vl);     //ch_1_out_0 += a1 * b0;
            vAcc3 = __riscv_vd4dots_vv_i32m2_tu(vAcc3, vA1_i8m2, vB1_i8m2, vl);     //ch_1_out_1 += a1 * b1;
            vAcc_wt_0 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_0, vA0_i8m2, vOne_i8m2, vl);    //sum_input_a0 += a0;
            vAcc_wt_1 = __riscv_vd4dots_vv_i32m2_tu(vAcc_wt_1, vA1_i8m2, vOne_i8m2, vl);    //sum_input_a1 += a1;
        }

        vl = __riscv_vsetvl_e32m2(num_col_a);
        vint32m1_t vSum_e0_0 = __riscv_vundefined_i32m1();
