        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V2, 1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V1, NDS_VEC_V3, 1);

        //add bias back
        if (bias)
        {
            NDS_VEC_VLW_V(NDS_VEC_V6, bias);
            bias += vl;
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V6);
            NDS_VEC_VADD_VV(NDS_VEC_V1, NDS_VEC_V1, NDS_VEC_V6);
