        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1, 1);

        //add bias back
        if (bias)
        {
            long bias_val = *bias++;
            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, bias_val);
        }

