        long out_mult_val = *out_mult,
             out_shift_val = 30 - *out_shift;

        NDS_VEC_VWMUL_VX(NDS_VEC_V2, NDS_VEC_V0, out_mult_val);
        NDS_VEC_VNSRA_WX(NDS_VEC_V2, NDS_VEC_V2, out_shift_val);
