        NDS_VEC_VMAX_VX(NDS_VEC_V2, NDS_VEC_V2, activation_min);
        NDS_VEC_VMIN_VX(NDS_VEC_V2, NDS_VEC_V2, activation_max);

        //narrowing and store the results
        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_VI(NDS_VEC_V2, NDS_VEC_V2, 0);
        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_VI(NDS_VEC_V2, NDS_VEC_V2, 0);
        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VSB_V(NDS_VEC_V2, out_0);
        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VSRA_VI(NDS_VEC_V2, NDS_VEC_V2, 8);
        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VSB_V(NDS_VEC_V2, out_1);
        out_0++;
        out_1++;
        out_mult++;
        out_shift++;
    }

    out_0 += output_ch;

    /* return the new output pointer with offset */
    return out_0;
