            ptr_b0 += SIMD_NUM_Q7;
            ptr_b1 += SIMD_NUM_Q7;
            col_count -= SIMD_NUM_Q7;
        }
        while (col_count > 0)
        {
            int8_t a0 = *ptr_a0++;
            int8_t b0 = *ptr_b0++;
            int8_t a1 = *ptr_a1++;
            int8_t b1 = *ptr_b1++;

            ch_0_out_0 += a0 * b0;
            ch_0_out_1 += a0 * b1;
            ch_1_out_0 += a1 * b0;
            ch_1_out_1 += a1 * b1;
            col_count--;
        }

        //add extra contribution back
        ch_0_out_0 += contri_buf[cur_row];
        ch_0_out_1 += contri_buf[cur_row];
        ch_1_out_0 += contri_buf[cur_row + 1];
        ch_1_out_1 += contri_buf[cur_row + 1];

        ch_0_out_0 = nn_requantize(ch_0_out_0, *out_scale, *out_shift);
        ch_0_out_0 += out_offset;
        ch_0_out_0 = MAX(ch_0_out_0, act_min);
        ch_0_out_0 = MIN(ch_0_out_0, act_max);
        *out_0++ = (int8_t)ch_0_out_0;

        ch_0_out_1 = nn_requantize(ch_0_out_1, *out_scale, *out_shift);
        ch_0_out_1 += out_offset;
        ch_0_out_1 = MAX(ch_0_out_1, act_min);
        ch_0_out_1 = MIN(ch_0_out_1, act_max);
        *out_1++ = (int8_t)ch_0_out_1;
        out_scale++;
        out_shift++;

        ch_1_out_0 = nn_requantize(ch_1_out_0, *out_scale, *out_shift);
        ch_1_out_0 += out_offset;
        ch_1_out_0 = MAX(ch_1_out_0, act_min);
        ch_1_out_0 = MIN(ch_1_out_0, act_max);
        *out_0++ = (int8_t)ch_1_out_0;

        ch_1_out_1 = nn_requantize(ch_1_out_1, *out_scale, *out_shift);
        ch_1_out_1 += out_offset;
        ch_1_out_1 = MAX(ch_1_out_1, act_min);
        ch_1_out_1 = MIN(ch_1_out_1, act_max);
        *out_1++ = (int8_t)ch_1_out_1;
        out_scale++;
        out_shift++;

        ptr_a0 += num_col_a;
    }

    /* compute the last odd numbered row if any */
    if (out_tensor_ch & 0x1)
    {
        /* setup pointers for B */
        const int8_t *ptr_b0 = input_b;
        const int8_t *ptr_b1 = ptr_b0 + num_col_a;

        long ch_0_out_0 = 0;
        long ch_0_out_1 = 0;

        int32_t col_count = num_col_a;
        while (col_count >= SIMD_NUM_Q7)
        {
            suni_t a0 = simd_load_8((s8_t*)ptr_a0, 0);
            suni_t b0 = simd_load_8((s8_t*)ptr_b0, 0);
            suni_t b1 = simd_load_8((s8_t*)ptr_b1, 0);

            ch_0_out_0 = NDS_DSP_SMAQA(ch_0_out_0, a0.l0, b0.l0);
            ch_0_out_1 = NDS_DSP_SMAQA(ch_0_out_1, a0.l0, b1.l0);

            ptr_a0 += SIMD_NUM_Q7;
            ptr_b0 += SIMD_NUM_Q7;
            ptr_b1 += SIMD_NUM_Q7;
            col_count -= SIMD_NUM_Q7;
        }
        while (col_count > 0)
        {
            int8_t a0 = *ptr_a0++;
            int8_t b0 = *ptr_b0++;
            int8_t b1 = *ptr_b1++;

            ch_0_out_0 += a0 * b0;
            ch_0_out_1 += a0 * b1;
            col_count--;
        }

        //add extra contribution back
        ch_0_out_0 += contri_buf[out_tensor_ch - 1];
        ch_0_out_1 += contri_buf[out_tensor_ch - 1];

        ch_0_out_0 = nn_requantize(ch_0_out_0, *out_scale, *out_shift);
        ch_0_out_0 += out_offset;
        ch_0_out_0 = MAX(ch_0_out_0, act_min);
        ch_0_out_0 = MIN(ch_0_out_0, act_max);
        *out_0++ = (int8_t)ch_0_out_0;

        ch_0_out_1 = nn_requantize(ch_0_out_1, *out_scale, *out_shift);
        ch_0_out_1 += out_offset;
        ch_0_out_1 = MAX(ch_0_out_1, act_min);
        ch_0_out_1 = MIN(ch_0_out_1, act_max);
        *out_1++ = (int8_t)ch_0_out_1;
        out_scale++;
        out_shift++;
    }

    out_0 += out_tensor_ch;

    /* return the new output pointer with offset */
    return out_0;
#else
    (void)input_a;
    (void)input_b;
    (void)out_tensor_ch;
    (void)out_shift;
    (void)out_scale;
    (void)out_offset;
    (void)act_min;
    (void)act_max;
    (void)num_col_a;
    (void)contri_buf;
    (void)out;
    /* To be completed */
    return NULL;
#endif
}

int8_t* nn_mat_mult_kernel_s8_offset_v4(const int8_t *input_a,
            const int8_t *input_b,
            const int32_t out_tensor_ch,
            const int32_t *out_shift,
            const int32_t *out_scale,
            const int32_t in_offset,    //value is in the range of [-127, 128]
            const int32_t out_offset,   //value is in the range of [-128, 127]
            const int32_t act_min,
            const int32_t act_max,
            const int32_t num_col_a,
            const int32_t *contri_buf,
            int8_t *out)
{
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
    // 4x2 tiled vd4dots GEMM: 4 output channels x 2 pixels per tile, LMUL=M2
    // Halves pixel data reloads compared to v2 (2x2 tile, LMUL=M4)
    (void)in_offset;

    /* set up the second output pointers */
    int8_t *out_0 = out;
    int8_t *out_1 = out_0 + out_tensor_ch;
    const int8_t *ptr_a0 = input_a;
    long vl;

    long maxvl_per_loop;
    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);

    // Register allocation (LMUL=M2):
    // Accumulators: v0(ch0*pix0), v2(ch0*pix1), v4(ch1*pix0), v6(ch1*pix1),
    //               v8(ch2*pix0), v10(ch2*pix1), v12(ch3*pix0), v14(ch3*pix1)
    // Load buffers: v16(pix0), v18(pix1), v20(wt0), v22(wt1), v24(wt2), v26(wt3)
    // Scratch: v28-v31

    for (long cur_row = 0; (cur_row + 4) <= out_tensor_ch; cur_row += 4)
    {
        /* setup pointers for B (im2col columns / pixels) */
        const int8_t *ptr_b0 = input_b;
        const int8_t *ptr_b1 = ptr_b0 + num_col_a;

        /* setup pointers for A (weight rows / channels) */
        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
        const int8_t *ptr_a2 = ptr_a1 + num_col_a;
        const int8_t *ptr_a3 = ptr_a2 + num_col_a;

        //init the 8 accumulators
        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V6, NDS_VEC_V6, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);

        long col_count = num_col_a;
        while(col_count >= maxvl_per_loop)
        {
            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
            // Load 2 pixel columns (reused across all 4 weight rows)
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_b1);
            // Load 4 weight rows
            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_a1);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a2);
            NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a3);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_a2 += vl;
            ptr_a3 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V20, NDS_VEC_V16);  //ch0*pix0
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V20, NDS_VEC_V18);  //ch0*pix1
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V22, NDS_VEC_V16);  //ch1*pix0
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V22, NDS_VEC_V18);  //ch1*pix1
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V16);  //ch2*pix0
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V24, NDS_VEC_V18);  //ch2*pix1
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V26, NDS_VEC_V16);  //ch3*pix0
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V26, NDS_VEC_V18);  //ch3*pix1
        }

        //extra process for the case of elements to be dot producted is not a mutiple of 4
        if(col_count > 0)
        {
            //clean pixel buffers to avoid junk in tail affecting vd4dots
            long tmp_avl;
            tmp_avl = col_count + 3;
            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VAND_VI(NDS_VEC_V18, NDS_VEC_V18, 0);

            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_b1);
            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_a1);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a2);
            NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a3);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_a2 += vl;
            ptr_a3 += vl;

            vl = (vl + 3) >> 2;
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V20, NDS_VEC_V16);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V20, NDS_VEC_V18);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V22, NDS_VEC_V16);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V22, NDS_VEC_V18);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V16);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V24, NDS_VEC_V18);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V26, NDS_VEC_V16);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V26, NDS_VEC_V18);
        }

        // === Reduction epilogue: 8 vredsum → pack to VL=4 → requantize ===
        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);

        // Reduce 8 accumulators to scalars in element [0]
        NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V0,  NDS_VEC_V31);  //ch0*pix0 → v16[0]
        NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V4,  NDS_VEC_V31);  //ch1*pix0 → v17[0]
        NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V8,  NDS_VEC_V31);  //ch2*pix0 → v18[0]
        NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V12, NDS_VEC_V31);  //ch3*pix0 → v19[0]
        NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V2,  NDS_VEC_V31);  //ch0*pix1 → v20[0]
        NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V6,  NDS_VEC_V31);  //ch1*pix1 → v21[0]
        NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V10, NDS_VEC_V31);  //ch2*pix1 → v22[0]
        NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V14, NDS_VEC_V31);  //ch3*pix1 → v23[0]

        // Pack 4 scalars into VL=4 vectors via vslideup
        // pix0: v16 = [ch0, ch1, ch2, ch3]
        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
        NDS_VEC_VSETVLI(vl, 3, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V22, 2);
        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V23, 3);

        // v16 = pix0 [ch0,ch1,ch2,ch3], v20 = pix1 [ch0,ch1,ch2,ch3]

        //add extra contribution back
        NDS_VEC_VLE32_V(NDS_VEC_V24, contri_buf);
        contri_buf += vl;
        NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
        NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V24);

        //===== Quantize down =====
        NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
        NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);

        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V3);
        NDS_VEC_VWMUL_VV(NDS_VEC_V6, NDS_VEC_V20, NDS_VEC_V3);
        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
        NDS_VEC_VNSRA_WV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V2);
        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
        NDS_VEC_VSSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 1);

        // Add offset
        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, out_offset);

        // Clamp the result
        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, act_min);
        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, act_max);

        //narrowing and store the results
        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
        NDS_VEC_VSE8_V(NDS_VEC_V4, out_0);
        NDS_VEC_VSE8_V(NDS_VEC_V6, out_1);
        out_0 += 4;
        out_1 += 4;
        out_scale += 4;
        out_shift += 4;

        ptr_a0 += 3 * (long)num_col_a;  // skip past channels 1,2,3
    }

    // === Handle remaining 2 channels (if out_tensor_ch % 4 >= 2) ===
    if ((out_tensor_ch & 0x3) >= 2)
    {
        const int8_t *ptr_b0 = input_b;
        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
        const int8_t *ptr_a1 = ptr_a0 + num_col_a;

        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);

        long maxvl_m4;
        NDS_VEC_VSETVLI(maxvl_m4, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);

        long col_count = num_col_a;
        while(col_count >= maxvl_m4)
        {
            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);
        }

        if(col_count > 0)
        {
            long tmp_avl = col_count + 3;
            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);
            NDS_VEC_VAND_VI(NDS_VEC_V28, NDS_VEC_V28, 0);

            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
            ptr_a0 += vl;
            ptr_a1 += vl;

            vl = (vl + 3) >> 2;
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);
        }

        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V4, NDS_VEC_V31);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V8, NDS_VEC_V31);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V12, NDS_VEC_V31);

        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V2, 1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V1, NDS_VEC_V3, 1);

        NDS_VEC_VLE32_V(NDS_VEC_V4, contri_buf);
        contri_buf += vl;
        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
        NDS_VEC_VADD_VV(NDS_VEC_V1, NDS_VEC_V1, NDS_VEC_V4);

        NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
        NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);

        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
        NDS_VEC_VWMUL_VV(NDS_VEC_V6, NDS_VEC_V1, NDS_VEC_V3);
        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
        NDS_VEC_VNSRA_WV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V2);
        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
        NDS_VEC_VSSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 1);

        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, out_offset);

        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, act_min);
        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, act_max);

        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
        NDS_VEC_VSE8_V(NDS_VEC_V4, out_0);
        NDS_VEC_VSE8_V(NDS_VEC_V6, out_1);
        out_0 += 2;
        out_1 += 2;
        out_scale += 2;
        out_shift += 2;

        ptr_a0 += num_col_a;
    }

    // === Handle remaining 1 channel (if out_tensor_ch is odd) ===
    if (out_tensor_ch & 0x1)
    {
        const int8_t *ptr_b0 = input_b;
        const int8_t *ptr_b1 = ptr_b0 + num_col_a;

        const long load_stride_byte = 0;
        const long store_stride_byte = sizeof(*out) * out_tensor_ch;

        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);

        long maxvl_m4;
        NDS_VEC_VSETVLI(maxvl_m4, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);

        long col_count = num_col_a;
        while(col_count >= maxvl_m4)
        {
            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
            ptr_a0 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);
        }

        if(col_count > 0)
        {
            long tmp_avl = col_count + 3;
            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);

            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
            ptr_a0 += vl;

            vl = (vl + 3) >> 2;
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);
        }

        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V4, NDS_VEC_V31);

        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1, 1);

        NDS_VEC_VLSE32_V(NDS_VEC_V4, contri_buf, load_stride_byte);
        contri_buf++;
        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);

        NDS_VEC_VLSE32_V(NDS_VEC_V2, out_shift, load_stride_byte);
        NDS_VEC_VLSE32_V(NDS_VEC_V3, out_scale, load_stride_byte);
        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);

        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);

        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);

        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);

        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
        NDS_VEC_VSSE8_V(NDS_VEC_V4, out_0, store_stride_byte);
        out_0++;
        out_scale++;
        out_shift++;
    }

    out_0 += out_tensor_ch;

    /* return the new output pointer with offset */
    return out_0;
#else
    // For non-VEC builds, delegate to v2
    return nn_mat_mult_kernel_s8_offset_v2(input_a, input_b, out_tensor_ch,
        out_shift, out_scale, in_offset, out_offset, act_min, act_max,
        num_col_a, contri_buf, out);
#endif
}

int8_t* nn_mat_mult_kernel_s8_offset_v3(const int8_t *input_a,
            const int8_t *input_b,
            const int32_t out_ch_per_group,
            const int32_t out_tensor_ch,
            const int32_t *out_shift,
            const int32_t *out_scale,
            const int32_t in_offset,    //value is in the range of [-127, 128]
            const int32_t out_offset,   //value is in the range of [-128, 127]
            const int32_t act_min,
            const int32_t act_max,
            const int32_t num_col_a,
            const int32_t num_col_a_aligned,
            const int32_t *contri_buf,
            int8_t *out)
{
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)    // unpack the 4-bit weight into a temporary buffer
    (void)in_offset;

    /* set up the second output pointers */
    int8_t *out_0 = out;
    int8_t *out_1 = out_0 + out_tensor_ch;
    const int8_t *ptr_a0 = input_a;
    long vl;

    long maxvl_per_loop;
    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);

    for (long cur_row = 0; (cur_row + 2) <= out_ch_per_group; cur_row += 2)
    {
        /* setup pointers for B */
        const int8_t *ptr_b0 = input_b;
        const int8_t *ptr_b1 = ptr_b0 + num_col_a;

        /* align the second pointer for A */
        const int8_t *ptr_a1 = ptr_a0 + num_col_a;

        //init the accumulator
        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);

        long col_count = num_col_a;
        while(col_count >= maxvl_per_loop)
        {
            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);   //ch_1_out_0 += a1 * b0;
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);  //ch_1_out_1 += a1 * b1;
        }

        //extra process for the case of elements to be dot producted is not a mutiple of 4
        if(col_count > 0)
        {
            //clean one of the dot product source
            long tmp_avl;
            tmp_avl = col_count + 3;
            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);
            NDS_VEC_VAND_VI(NDS_VEC_V28, NDS_VEC_V28, 0);

            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
            ptr_a0 += vl;
            ptr_a1 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            vl = (vl + 3) >> 2;
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);   //ch_1_out_0 += a1 * b0;
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);  //ch_1_out_1 += a1 * b1;
        }

        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);   //note the avl here
        NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);    //ch_0_out_0
        NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V4, NDS_VEC_V31);    //ch_0_out_1
        NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V8, NDS_VEC_V31);    //ch_1_out_0
        NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V12, NDS_VEC_V31);   //ch_1_out_1

        long ch_0_out_0, ch_0_out_1, ch_1_out_0, ch_1_out_1;
        NDS_VEC_VMV_X_S(ch_0_out_0, NDS_VEC_V0);
        NDS_VEC_VMV_X_S(ch_0_out_1, NDS_VEC_V1);
        NDS_VEC_VMV_X_S(ch_1_out_0, NDS_VEC_V2);
        NDS_VEC_VMV_X_S(ch_1_out_1, NDS_VEC_V3);

        // add extra contribution back
        ch_0_out_0 += contri_buf[cur_row];
        ch_0_out_1 += contri_buf[cur_row];
        ch_1_out_0 += contri_buf[cur_row + 1];
        ch_1_out_1 += contri_buf[cur_row + 1];

        // Quantize down
        ch_0_out_0 = nn_requantize(ch_0_out_0, out_scale[0], out_shift[0]);
        ch_0_out_1 = nn_requantize(ch_0_out_1, out_scale[0], out_shift[0]);
        ch_1_out_0 = nn_requantize(ch_1_out_0, out_scale[1], out_shift[1]);
        ch_1_out_1 = nn_requantize(ch_1_out_1, out_scale[1], out_shift[1]);

        // Add offset
        ch_0_out_0 += out_offset;
        ch_0_out_1 += out_offset;
        ch_1_out_0 += out_offset;
        ch_1_out_1 += out_offset;

        // Clamp the result
        ch_0_out_0 = MAX(ch_0_out_0, act_min);
        ch_0_out_0 = MIN(ch_0_out_0, act_max);
        ch_0_out_1 = MAX(ch_0_out_1, act_min);
        ch_0_out_1 = MIN(ch_0_out_1, act_max);
        ch_1_out_0 = MAX(ch_1_out_0, act_min);
        ch_1_out_0 = MIN(ch_1_out_0, act_max);
        ch_1_out_1 = MAX(ch_1_out_1, act_min);
        ch_1_out_1 = MIN(ch_1_out_1, act_max);

        out_0[0] = ch_0_out_0;
        out_1[0] = ch_0_out_1;
        out_0[1] = ch_1_out_0;
        out_1[1] = ch_1_out_1;
        out_0 += 2;
        out_1 += 2;
        out_scale += 2;
        out_shift += 2;

        ptr_a0 += num_col_a;
    }

    /* compute the last odd numbered row if any */
    if (out_ch_per_group & 0x1)
    {
        /* setup pointers for B */
        const int8_t *ptr_b0 = input_b;
        const int8_t *ptr_b1 = ptr_b0 + num_col_a;

        //init the accumulator
        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);

        long col_count = num_col_a;
        while(col_count >= maxvl_per_loop)
        {
            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
            ptr_a0 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
        }

        //extra process for the case of elements to be dot producted is not a mutiple of 4
        if(col_count > 0)
        {
            //clean one of the dot product source
            long tmp_avl;
            tmp_avl = col_count + 3;
            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);

            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
            ptr_a0 += vl;
            ptr_b0 += vl;
            ptr_b1 += vl;
            col_count -= vl;

            vl = (vl + 3) >> 2;
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
        }

        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
